"use client";

import { useCallback, useRef } from "react";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";
import { useScrollProgress } from "../hooks/useScrollProgress";

/**
 * Section 02 — the exploded axonometric, scrubbed by scroll. THE SIGNATURE.
 *
 * A hanok is a section drawing before it is a plan: the roof (처마/지붕),
 * the great beam (대들보), the columns (기둥), the maru floor (마루), and
 * the foundation stones (주춧돌) stack in a clear vertical order, joined
 * by mortise-and-tenon (장부이음) — no nails. The page disassembles that
 * stack into an exploded axonometric as you scroll: each layer separates
 * axially, the callout lines draw in (stroke-dashoffset, pathLength=1),
 * and the bilingual labels settle beside their part.
 *
 * Travel ratios sell the Z-axis: roof and foundation (the outer planes)
 * move 3.4× farther than the beams/columns/floor sandwiched between them —
 * the same parallax logic as a real exploded architectural diagram.
 *
 * The server-rendered state is the ASSEMBLED hanok section with all
 * callouts drawn and labels visible. No-JS and reduced-motion simply keep
 * that state (the CSS collapses the 320vh runway). Under 720px the
 * in-SVG callouts hand off to an HTML legend.
 *
 * Motion is transform (translateY per layer), stroke-dashoffset (callouts),
 * and opacity (labels) only — never layout. The scrub is rAF-throttled and
 * parked offscreen (gate G3, via useScrollProgress).
 */

type Layer = {
  id: string;
  /** assembled center y of the layer, viewBox units */
  cy: number;
  /** full-explode travel: signed px the layer moves at p=1.
      Outer planes (roof/foundation) travel ~3.4× the inner planes. */
  spread: number;
  /** drawing window for the callout, staggered by index */
  drawStart: number;
  label: string;
  labelKr: string;
  gloss: string;
  glossKr: string;
  /** the callout the eave-red "key" line points at (the mortise) */
  key?: boolean;
};

const LAYERS: Layer[] = [
  {
    id: "roof",
    cy: 120,
    spread: -168,
    drawStart: 0.3,
    label: "CURVED-EAVE ROOF",
    labelKr: "처마 · 지붕",
    gloss: "tiles on a ridge beam",
    glossKr: "용마루 위 기와",
  },
  {
    id: "beam",
    cy: 210,
    spread: -86,
    drawStart: 0.37,
    label: "GREAT BEAM",
    labelKr: "대들보",
    gloss: "spans column to column",
    glossKr: "기둥 사이를 잇는 큰 들보",
    key: true,
  },
  {
    id: "column",
    cy: 320,
    spread: -44,
    drawStart: 0.44,
    label: "COLUMNS",
    labelKr: "기둥",
    gloss: "tenoned into the stones",
    glossKr: "주춧돌에 장부로 세운 기둥",
  },
  {
    id: "floor",
    cy: 410,
    spread: 96,
    drawStart: 0.51,
    label: "MARU FLOOR",
    labelKr: "마루",
    gloss: "the raised wooden hall",
    glossKr: "높여 깐 마루바닥",
  },
  {
    id: "foundation",
    cy: 470,
    spread: 168,
    drawStart: 0.58,
    label: "FOUNDATION STONES",
    labelKr: "주춧돌",
    gloss: "the building rests on stone",
    glossKr: "집이 돌 위에 앉는다",
  },
];

/** Explode timing: plates separate while p ∈ [0.06, 0.78]. */
const EXPLODE_START = 0.06;
const EXPLODE_SPAN = 0.72;
const DRAW_SPAN = 0.18;

const clamp01 = (v: number) => Math.min(1, Math.max(0, v));
const smoothstep = (v: number) => v * v * (3 - 2 * v);

export default function ExplodedAxonometric() {
  const sectionRef = useRef<HTMLElement | null>(null);
  const groupRefs = useRef<Array<SVGGElement | null>>([]);
  const lineRefs = useRef<Array<SVGPathElement | null>>([]);
  const labelRefs = useRef<Array<SVGGElement | null>>([]);
  const reduced = usePrefersReducedMotion();

  const apply = useCallback((p: number) => {
    const e = smoothstep(clamp01((p - EXPLODE_START) / EXPLODE_SPAN));
    LAYERS.forEach((layer, i) => {
      const g = groupRefs.current[i];
      if (g) {
        // translate3d — compositor-friendly, no layout.
        g.style.transform = `translate3d(0, ${(layer.spread * e).toFixed(2)}px, 0)`;
      }
      const t = clamp01((p - layer.drawStart) / DRAW_SPAN);
      const line = lineRefs.current[i];
      if (line) line.style.strokeDashoffset = String(1 - t);
      const label = labelRefs.current[i];
      if (label) label.style.opacity = String(clamp01(t * 1.5));
    });
  }, []);

  useScrollProgress(sectionRef, apply, !reduced);

  return (
    <section
      ref={sectionRef}
      className="hanok-explode"
      aria-labelledby="hanok-explode-title"
    >
      <div className="hanok-explode__sticky">
        <div className="hanok-sechead">
          <span className="hanok-sechead__no" aria-hidden="true">
            02
          </span>
          <h2 className="hanok-sechead__title" id="hanok-explode-title">
            The building, taken apart{" "}
            <span lang="ko">집을 분해하다</span>
          </h2>
          <p className="hanok-sechead__note">
            Keep scrolling — it opens.{" "}
            <span lang="ko">스크롤하면 열립니다.</span>
          </p>
        </div>

        <svg
          className="hanok-explode__svg"
          viewBox="0 0 760 620"
          role="img"
          aria-label="Exploded axonometric of the hanok: curved-eave roof, great beam, columns, maru floor, and foundation stones separate as you scroll, each labeled with its Korean name and joined by mortise-and-tenon. 한옥의 폭발 등각 투상도 — 처마, 대들보, 기둥, 마루, 주춧돌이 스크롤에 따라 벌어지며, 각각의 한국어 이름과 장부이음 결구가 드러난다."
        >
          {/* a faint blueprint baseline — the ground the building sites on */}
          <line
            x1="80"
            y1="540"
            x2="680"
            y2="540"
            stroke="var(--hanok-hairline)"
            strokeWidth="1"
            strokeDasharray="2 5"
          />

          {LAYERS.map((layer, i) => (
            <g
              key={layer.id}
              ref={(el) => {
                groupRefs.current[i] = el;
              }}
              className={`hanok-layer hanok-layer--${layer.id}`}
            >
              {renderLayer(layer)}

              {/* the callout travels with its layer so it always points at the part */}
              <g
                className="hanok-callout"
                ref={(el) => {
                  labelRefs.current[i] = el;
                }}
              >
                <path
                  ref={(el) => {
                    lineRefs.current[i] = el;
                  }}
                  className={`hanok-callout__line${layer.key ? " hanok-callout__line--key" : ""}`}
                  d={calloutPath(layer)}
                  pathLength={1}
                  strokeDasharray={1}
                  strokeDashoffset={0}
                />
                <circle
                  className="hanok-callout__dot"
                  cx={calloutDot(layer).x}
                  cy={calloutDot(layer).y}
                  r={3}
                />
                <text
                  className="hanok-callout__label"
                  x={calloutLabel(layer).x}
                  y={calloutLabel(layer).y}
                  textAnchor={calloutLabel(layer).anchor}
                >
                  {layer.label}
                </text>
                <text
                  className="hanok-callout__kr"
                  lang="ko"
                  x={calloutLabel(layer).x}
                  y={calloutLabel(layer).y + 18}
                  textAnchor={calloutLabel(layer).anchor}
                >
                  {layer.labelKr}
                </text>
                <text
                  className="hanok-callout__kr-gloss"
                  x={calloutLabel(layer).x}
                  y={calloutLabel(layer).y + 34}
                  textAnchor={calloutLabel(layer).anchor}
                >
                  {layer.gloss}
                </text>
              </g>
            </g>
          ))}
        </svg>

        {/* Narrow screens read this instead of the in-SVG callouts. */}
        <ol className="hanok-explode__legend">
          {LAYERS.map((layer) => (
            <li key={layer.id}>
              <span className="hanok-legend__gloss">
                {layer.label}
                <br />
                <span className="hanok-legend__kr" lang="ko">
                  {layer.labelKr}
                </span>
                <br />
                <span>{layer.gloss}</span>
              </span>
            </li>
          ))}
        </ol>
      </div>
    </section>
  );
}

/** The geometry of each layer, centered on its assembled cy. */
function renderLayer(layer: Layer) {
  switch (layer.id) {
    case "roof":
      return (
        <g className="hanok-roof">
          {/* the curved-eave roof: a broad bowed trapezoid with upturned tips,
              ridge on top, tile courses implied by horizontal bands. */}
          {/* roof body — curved eave silhouette via a path */}
          <path
            className="hanok-roof__tile"
            d={`
              M 140 ${layer.cy + 26}
              Q 130 ${layer.cy + 22}, 122 ${layer.cy + 30}
              L 110 ${layer.cy + 38}
              Q 200 ${layer.cy - 30}, 380 ${layer.cy - 34}
              Q 560 ${layer.cy - 30}, 650 ${layer.cy + 38}
              L 638 ${layer.cy + 30}
              Q 630 ${layer.cy + 22}, 620 ${layer.cy + 26}
              Q 500 ${layer.cy + 14}, 380 ${layer.cy + 12}
              Q 260 ${layer.cy + 14}, 140 ${layer.cy + 26}
              Z
            `}
          />
          {/* ridge beam on top */}
          <rect
            className="hanok-roof__ridge"
            x="200"
            y={layer.cy - 40}
            width="360"
            height="10"
            rx="3"
          />
          {/* the dancheong eave trim — the one red, tracing both upturned tips */}
          <path
            className="hanok-roof__eave-trim"
            d={`M 122 ${layer.cy + 30} Q 116 ${layer.cy + 40}, 128 ${layer.cy + 44}`}
          />
          <path
            className="hanok-roof__eave-trim"
            d={`M 638 ${layer.cy + 30} Q 644 ${layer.cy + 40}, 632 ${layer.cy + 44}`}
          />
          {/* rafter ends peeking under the eave */}
          <line className="hanok-roof__rafter" x1="150" y1={layer.cy + 30} x2="150" y2={layer.cy + 40} />
          <line className="hanok-roof__rafter" x1="190" y1={layer.cy + 26} x2="190" y2={layer.cy + 36} />
          <line className="hanok-roof__rafter" x1="570" y1={layer.cy + 26} x2="570" y2={layer.cy + 36} />
          <line className="hanok-roof__rafter" x1="610" y1={layer.cy + 30} x2="610" y2={layer.cy + 40} />
        </g>
      );
    case "beam":
      return (
        <g className="hanok-beam">
          {/* the great beam (대들보): a long timber spanning column to column,
              with the tenons (장부) protruding at both ends — the joinery that
              the eave-red key callout points at. */}
          <rect
            className="hanok-beam__timber"
            x="150"
            y={layer.cy - 16}
            width="460"
            height="32"
            rx="4"
          />
          {/* tenon protrusions — the mortise-and-tenon detail */}
          <rect className="hanok-beam__tenon" x="138" y={layer.cy - 8} width="16" height="16" rx="2" />
          <rect className="hanok-beam__tenon" x="606" y={layer.cy - 8} width="16" height="16" rx="2" />
          {/* a center notch — where the ridge post would tenon in */}
          <line
            x1="374"
            y1={layer.cy - 16}
            x2="386"
            y2={layer.cy - 16}
            stroke="var(--hanok-beam)"
            strokeWidth="2"
          />
        </g>
      );
    case "column":
      return (
        <g className="hanok-column">
          {/* four columns (기둥), evenly spaced, each tenoned top and bottom */}
          {[150, 280, 410, 540].map((cx) => (
            <g key={cx}>
              <rect
                className="hanok-column__post"
                x={cx - 14}
                y={layer.cy - 70}
                width="28"
                height="140"
                rx="3"
              />
              {/* top tenon */}
              <rect
                className="hanok-beam__tenon"
                x={cx - 6}
                y={layer.cy - 78}
                width="12"
                height="10"
                rx="1.5"
              />
              {/* bottom tenon — into the foundation stone */}
              <rect
                className="hanok-beam__tenon"
                x={cx - 6}
                y={layer.cy + 68}
                width="12"
                height="10"
                rx="1.5"
              />
            </g>
          ))}
          {/* the enclosed earthen wall (흙벽) between the columns — warm fill */}
          <rect
            className="hanok-wall__fill"
            x="164"
            y={layer.cy - 64}
            width="376"
            height="128"
            opacity="0.45"
          />
        </g>
      );
    case "floor":
      return (
        <g className="hanok-floor">
          {/* the maru floor (마루): raised wooden deck with plank lines */}
          <rect
            className="hanok-floor__maru"
            x="120"
            y={layer.cy - 12}
            width="520"
            height="24"
            rx="2"
          />
          {/* plank seams — the maru's recessed floorboards */}
          {[180, 240, 300, 360, 420, 480, 540, 600].map((px) => (
            <line
              key={px}
              className="hanok-floor__plank"
              x1={px}
              y1={layer.cy - 12}
              x2={px}
              y2={layer.cy + 12}
            />
          ))}
        </g>
      );
    case "foundation":
      return (
        <g className="hanok-foundation">
          {/* four foundation stones (주춧돌), one per column */}
          {[150, 280, 410, 540].map((cx) => (
            <rect
              key={cx}
              className="hanok-foundation__stone"
              x={cx - 28}
              y={layer.cy - 14}
              width="56"
              height="28"
              rx="4"
            />
          ))}
          {/* a mortise socket hinted on each stone — where the column tenons in */}
          {[150, 280, 410, 540].map((cx) => (
            <rect
              key={cx}
              x={cx - 7}
              y={layer.cy - 16}
              width="14"
              height="6"
              rx="1"
              fill="var(--hanok-paper)"
              stroke="var(--hanok-beam)"
              strokeWidth="0.8"
            />
          ))}
        </g>
      );
    default:
      return null;
  }
}

/** Each layer's callout line geometry — start at the part, kink, run out
    to the label. Right-side layers label right, left-side label left,
    so labels never collide across the spread. */
function calloutPath(layer: Layer): string {
  const right = layer.id === "roof" || layer.id === "beam" || layer.id === "floor";
  const startX = right ? 650 : 110;
  const kinkX = right ? 690 : 70;
  const endX = right ? 730 : 30;
  return `M ${startX} ${layer.cy} H ${kinkX} L ${endX} ${layer.cy}`;
}

function calloutDot(layer: Layer): { x: number; y: number } {
  const right = layer.id === "roof" || layer.id === "beam" || layer.id === "floor";
  return { x: right ? 650 : 110, y: layer.cy };
}

function calloutLabel(layer: Layer): { x: number; y: number; anchor: "start" | "end" } {
  const right = layer.id === "roof" || layer.id === "beam" || layer.id === "floor";
  return {
    x: right ? 700 : 60,
    y: layer.cy - 8,
    anchor: right ? "start" : "end",
  };
}

"use client";

import { SEASONS, type useSeason } from "../hooks/useSeason";

type SeasonApi = ReturnType<typeof useSeason>;

/**
 * Section 04 — the seasonal-light control.
 *
 * The courtyard (madang) is open to the sky, so it changes with the season.
 * This toggle lets the visitor choose spring / summer / autumn / winter,
 * or leave the page to auto-cycle (one season per ~5.2s). Picking a season
 * stops the cycle; the AUTO button resumes it (unless reduced motion, in
 * which case the cycle is already frozen and AUTO is inert).
 *
 * The actual recolor happens in CSS via `data-season` on the root (set in
 * useSeason/page.tsx) — only the madang sky ground and the eave-shadow
 * angle change; wood grain, earth wall, and all text hold still, because
 * wood and earth don't change with the season, only the light does.
 *
 * Accessibility: a real segmented control. Each option is a <button> with
 * aria-pressed; the AUTO toggle is its own button. All keyboard-reachable,
 * with the eave-red focus ring. No hover-only behavior — auto-cycle keeps
 * the page alive on touch devices with no pointer at all.
 */
export default function SeasonalLight({ season }: { season: SeasonApi }) {
  return (
    <section className="hanok-season" aria-labelledby="hanok-season-title">
      <div className="hanok-sechead">
        <span className="hanok-sechead__no" aria-hidden="true">
          04
        </span>
        <h2 className="hanok-sechead__title" id="hanok-season-title">
          Four lights on one courtyard{" "}
          <span lang="ko">한 마당에 네 빛</span>
        </h2>
        <p className="hanok-sechead__note">
          Wood holds still; only the light moves.{" "}
          <span lang="ko">나무는 그대로, 빛만 움직인다.</span>
        </p>
      </div>

      <div className="hanok-season__bar" role="group" aria-label="Season · 계절">
        {SEASONS.map((s) => {
          const active = season.season === s.id && !season.auto;
          return (
            <button
              key={s.id}
              type="button"
              className="hanok-season__opt"
              aria-pressed={active}
              onClick={() => season.pick(s.id)}
            >
              {s.en}
              <span lang="ko">{s.ko}</span>
            </button>
          );
        })}

        <button
          type="button"
          className="hanok-season__auto"
          aria-pressed={season.auto}
          aria-label="Auto-cycle seasons · 계절 자동 순환"
          onClick={season.resume}
          disabled={season.reduced}
        >
          AUTO
        </button>
      </div>

      <p className="hanok-season__note">
        {season.reduced
          ? "Reduced motion: season held still. "
          : season.auto
            ? "The courtyard cycles on its own — pick one to hold it. "
            : "Held. Press AUTO to let it cycle again. "}
        <span lang="ko">
          {season.reduced
            ? "모션 감소: 계절은 멈춰 있다."
            : season.auto
              ? "마당이 저절로 돈다 — 하나를 고르면 멈춘다."
              : "고정됨. AUTO를 누르면 다시 돈다."}
        </span>
      </p>
    </section>
  );
}

import { Nanum_Myeongjo, Noto_Serif_KR, JetBrains_Mono } from "next/font/google";

/**
 * The three voices of the hanok atelier — Korean is the first language:
 *
 * Noto Serif KR — the structural face: section titles, the hanja and
 * Hangul of the building's parts (처마, 대들보, 기둥, 마루, 주춧돌). A serif
 * reads as architectural — load-bearing, cut into the wood, not floating.
 *
 * Nanum Myeongjo — display Hangul for the hero name 한옥 and zone headings;
 * a heavier, more carved-serif myungjo than Noto Serif KR's body voice.
 *
 * JetBrains Mono — the blueprint/joinery annotations: layer callouts,
 * mortise-and-tenon dimensions, season labels. The draftsman's pencil.
 *
 * styles.css consumes these as var(--font-noto-kr) / var(--font-nanum) /
 * var(--font-jbmono); page.tsx applies the .variable classes on the root.
 * All three declare ["latin"] for subsetting; Hangul ships via unicode-range
 * CSS so nothing preloadable is missed.
 */
export const notoSerifKr = Noto_Serif_KR({
  weight: ["400", "500", "700"],
  subsets: ["latin"],
  variable: "--font-noto-kr",
  display: "swap",
});

export const nanumMyeongjo = Nanum_Myeongjo({
  weight: ["400", "700", "800"],
  subsets: ["latin"],
  variable: "--font-nanum",
  display: "swap",
});

export const jetbrainsMono = JetBrains_Mono({
  subsets: ["latin"],
  variable: "--font-jbmono",
  display: "swap",
});

"use client";

import { useMemo } from "react";

export type CharToken = {
  /** the visible glyph (a single char, or whitespace collapsed to a space) */
  ch: string;
  /** true for non-space glyphs — only these get the per-glyph animation */
  glyph: boolean;
  /** stable key */
  key: string;
};

/**
 * Splits a string into per-glyph tokens for the character-split reveal
 * (technique tag `char-split-reveal`). Whitespace is preserved as a single
 * space token (no animation) so words keep their internal rhythm; every
 * other char becomes a glyph token.
 *
 * Accessibility contract (held by the caller):
 *   - the container carries the full text in `aria-label`,
 *   - the rendered spans are `aria-hidden="true"`,
 *   so a screen reader announces the string once, intact, while sighted
 *   visitors see each glyph settle into place. This hook only produces the
 *   token array; it does not render.
 */
export function useCharSplit(text: string): CharToken[] {
  return useMemo(() => {
    const out: CharToken[] = [];
    let i = 0;
    for (const ch of Array.from(text)) {
      // Array.from splits on code points — safe for Hangul syllables and
      // combining marks; a Hangul jamo cluster is rare in copy and the
      // fallback (whole syllable as one glyph) is the right granularity.
      if (/\s/.test(ch)) {
        out.push({ ch: " ", glyph: false, key: `s${i}` });
      } else {
        out.push({ ch, glyph: true, key: `g${i}` });
      }
      i += 1;
    }
    return out;
  }, [text]);
}

"use client";

import { useSyncExternalStore } from "react";

const QUERY = "(prefers-reduced-motion: reduce)";

function subscribe(onChange: () => void): () => void {
  const mql = window.matchMedia(QUERY);
  mql.addEventListener("change", onChange);
  return () => mql.removeEventListener("change", onChange);
}

function getSnapshot(): boolean {
  return window.matchMedia(QUERY).matches;
}

function getServerSnapshot(): boolean {
  return false;
}

/**
 * True when the OS asks for reduced motion.
 * SSR-safe: the server snapshot is `false`; on the client the real value is
 * read synchronously, and live changes to the setting re-render immediately.
 * The hanok honors this by parking every scroll-scrub at the assembled state,
 * freezing the season, and snapping zone reveals — the page is still a
 * complete, readable structure.
 */
export function usePrefersReducedMotion(): boolean {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

"use client";

import { useEffect, useRef } from "react";
import { usePrefersReducedMotion } from "./usePrefersReducedMotion";

/**
 * Reveals descendants marked with `data-reveal` as they scroll into view,
 * by adding the `is-shown` class. Returns a ref to attach to a container
 * (the zones section root).
 *
 * The pre-reveal state (opacity/translate) lives in styles.css and is gated
 * behind the `.hanok-js` root class, so every zone is fully visible when
 * JavaScript never runs (the SSR state is the finished page). Under
 * prefers-reduced-motion the observer still runs but the CSS parks the
 * transition, so zones appear at rest either way.
 *
 * Elements that intersect in the same observer batch are staggered 100ms
 * apart via transition-delay, so a screenful of zones never rises as one
 * slab. The whole page uses one observer (perf gate G3: nothing per-zone).
 *
 * This imperative pattern (ref + classList, no state read in render) is
 * chosen deliberately over a `{ref, shown}` tuple because it keeps the ref
 * out of render — the lint rule that guards refs-during-render stays clean,
 * and there is nothing for React to re-render on intersection.
 */
export function useReveal<T extends HTMLElement>() {
  const rootRef = useRef<T | null>(null);
  const reduced = usePrefersReducedMotion();

  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;
    const targets = Array.from(
      root.querySelectorAll<HTMLElement>("[data-reveal]"),
    );

    if (!("IntersectionObserver" in window)) {
      for (const el of targets) el.classList.add("is-shown");
      return;
    }

    if (reduced) {
      // Reduced motion: show everything at rest. The CSS will not transition.
      for (const el of targets) el.classList.add("is-shown");
      return;
    }

    const io = new IntersectionObserver(
      (hits) => {
        let batch = 0;
        for (const hit of hits) {
          if (!hit.isIntersecting) continue;
          const el = hit.target as HTMLElement;
          el.style.transitionDelay = `${batch * 100}ms`;
          el.classList.add("is-shown");
          io.unobserve(el);
          batch += 1;
        }
      },
      { threshold: 0.14, rootMargin: "0px 0px -8% 0px" },
    );
    for (const el of targets) io.observe(el);
    return () => io.disconnect();
  }, [reduced]);

  return rootRef;
}

"use client";

import { useEffect, useRef, type RefObject } from "react";

/**
 * Drives `onProgress` with the 0→1 progress of a tall section scrolling
 * through the viewport: 0 while the section top is at or below the top of
 * the screen, 1 once its bottom has reached the bottom — the classic
 * "sticky stage inside an over-tall section" scrub window.
 *
 * rAF-throttled: scroll/resize/visibility only schedule a frame; the single
 * getBoundingClientRect read and all style writes happen together inside
 * that frame, so the scrub never interleaves layout reads and writes.
 *
 * Offscreen pause: an IntersectionObserver keeps the rAF loop parked unless
 * the section is actually intersecting the viewport (rubric gate G3). Tab
 * hidden via visibilitychange also parks it.
 *
 * When `enabled` is false (reduced motion) nothing is measured and nothing
 * ever fires — the DOM stays in its static, server-rendered (assembled)
 * state.
 */
export function useScrollProgress<T extends HTMLElement>(
  targetRef: RefObject<T | null>,
  onProgress: (p: number) => void,
  enabled: boolean,
): void {
  const callbackRef = useRef(onProgress);

  useEffect(() => {
    callbackRef.current = onProgress;
  });

  useEffect(() => {
    if (!enabled) return;
    const el = targetRef.current;
    if (!el) return;

    let raf = 0;
    let scheduled = false;
    let visible = false;

    const measure = () => {
      scheduled = false;
      const rect = el.getBoundingClientRect();
      const range = rect.height - window.innerHeight;
      if (range <= 0) {
        callbackRef.current(rect.top <= 0 ? 1 : 0);
        return;
      }
      const p = Math.min(1, Math.max(0, -rect.top / range));
      callbackRef.current(p);
    };

    const schedule = () => {
      if (!visible) return; // parked while offscreen
      if (document.hidden) return; // parked while tab hidden
      if (scheduled) return;
      scheduled = true;
      raf = window.requestAnimationFrame(measure);
    };

    // Park the loop unless the section is actually on screen.
    const io = new IntersectionObserver(
      (entries) => {
        visible = entries[0]?.isIntersecting ?? false;
        if (visible) schedule();
      },
      { rootMargin: "100px 0px" },
    );
    io.observe(el);

    const onVisibility = () => {
      if (!document.hidden) schedule();
    };

    schedule(); // settle the initial position without waiting for a scroll
    window.addEventListener("scroll", schedule, { passive: true });
    window.addEventListener("resize", schedule);
    document.addEventListener("visibilitychange", onVisibility);
    return () => {
      window.cancelAnimationFrame(raf);
      window.removeEventListener("scroll", schedule);
      window.removeEventListener("resize", schedule);
      document.removeEventListener("visibilitychange", onVisibility);
      io.disconnect();
    };
  }, [enabled, targetRef]);
}

"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import { usePrefersReducedMotion } from "./usePrefersReducedMotion";

export type Season = "spring" | "summer" | "autumn" | "winter";

export const SEASONS: Array<{
  id: Season;
  /** i18n label pair — the toggle reads both. */
  en: string;
  ko: string;
  /** short haiku for the madang, bilingual. */
  haikuEn: string;
  haikuKo: string;
}> = [
  {
    id: "spring",
    en: "Spring",
    ko: "봄",
    haikuEn: "Warmth returns to the floor.",
    haikuKo: "온돌에 봄이 돌아온다.",
  },
  {
    id: "summer",
    en: "Summer",
    ko: "여름",
    haikuEn: "The maru breathes through.",
    haikuKo: "마루로 바람이 지난다.",
  },
  {
    id: "autumn",
    en: "Autumn",
    ko: "가을",
    haikuEn: "Eaves cast long amber.",
    haikuKo: "처마 그림자 길어진다.",
  },
  {
    id: "winter",
    en: "Winter",
    ko: "겨울",
    haikuEn: "Snow rests on the tiles.",
    haikuKo: "기와 위 눈이 내린다.",
  },
];

const ORDER: Season[] = ["spring", "summer", "autumn", "winter"];
const CYCLE_MS = 5200; // one season per ~5.2s in auto mode

/**
 * Season state for the page. Two sources of truth, one value:
 *  - the visitor picks a season with the SeasonalLight toggle (manual),
 *  - or the page auto-cycles when `auto` is true.
 *
 * Auto-cycle is a `setInterval` that advances one step at a time. It pauses
 * entirely under prefers-reduced-motion (the season is then fixed at the
 * last manual pick, or spring by default) and when the tab is hidden — so
 * a backgrounded tab never burns a timer (gate G3). The interval is cleared
 * the instant the visitor takes manual control.
 *
 * The season is also reflected onto the root as `data-season` so CSS can
 * recolor the madang sky and drift the eave shadow without React re-render
 * — only background-color / transform / opacity transition (gate G3).
 */
export function useSeason() {
  const reduced = usePrefersReducedMotion();
  const [auto, setAuto] = useState(true);
  const [season, setSeason] = useState<Season>("spring");

  // Reflect onto the root for CSS (imperative — not React state the tree
  // needs to re-render for; the consumers that DO need it read `season`).
  useEffect(() => {
    const root = document.querySelector(".hanok-root");
    if (root) root.setAttribute("data-season", season);
  }, [season]);

  useEffect(() => {
    if (!auto) return;
    if (reduced) return; // frozen season under reduced motion
    let timer = window.setInterval(() => {
      setSeason((prev) => {
        const i = ORDER.indexOf(prev);
        return ORDER[(i + 1) % ORDER.length];
      });
    }, CYCLE_MS);

    const onVisibility = () => {
      if (document.hidden) {
        window.clearInterval(timer);
      } else {
        window.clearInterval(timer);
        timer = window.setInterval(() => {
          setSeason((prev) => {
            const i = ORDER.indexOf(prev);
            return ORDER[(i + 1) % ORDER.length];
          });
        }, CYCLE_MS);
      }
    };
    document.addEventListener("visibilitychange", onVisibility);
    return () => {
      window.clearInterval(timer);
      document.removeEventListener("visibilitychange", onVisibility);
    };
  }, [auto, reduced]);

  const pick = useCallback((next: Season) => {
    setAuto(false);
    setSeason(next);
  }, []);

  const resume = useCallback(() => {
    if (!reduced) setAuto(true);
  }, [reduced]);

  return useMemo(
    () => ({ season, auto, reduced, pick, resume }),
    [season, auto, reduced, pick, resume],
  );
}

"use client";

import { useEffect, useRef } from "react";
import "./styles.css";
import { jetbrainsMono, nanumMyeongjo, notoSerifKr } from "./fonts";
import Hero from "./components/Hero";
import ExplodedAxonometric from "./components/ExplodedAxonometric";
import ClimateZones from "./components/ClimateZones";
import SeasonalLight from "./components/SeasonalLight";
import JoineryDetail from "./components/JoineryDetail";
import HanokFooter from "./components/HanokFooter";
import { useSeason } from "./hooks/useSeason";

/**
 * HANOK — 한옥 / the building is the layout.
 * A heritage atelier (Jipdam Atelier · 집담) documents a Korean hanok whose
 * wooden structure becomes the page structure: the mortise-and-tenon joinery
 * (no nails — pieces interlock) is the grid, and the page flows through
 * distinct climate zones — the warm ondol room (온돌방), the cool maru hall
 * (마루), and the open madang courtyard (마당) — under seasonal light.
 *
 * `.hanok-js` is added on mount so every animated pre-state (unsettled
 * glyphs, undrawn eave, exploded runway, unrisen zones) is JS-gated. With
 * JavaScript disabled the page is the finished structure: glyphs at rest,
 * the eave drawn, the diagram assembled and labeled, every zone visible,
 * the season fixed at spring. Nothing is hidden behind a script.
 *
 * Season state lives here so the SeasonalLight toggle and the madang zone
 * share one source of truth; it is reflected to `data-season` on the root
 * for CSS.
 */
export default function HanokPage() {
  const rootRef = useRef<HTMLDivElement | null>(null);
  const season = useSeason();

  useEffect(() => {
    // Imperative on purpose: the class is a signal to CSS that JS is alive,
    // not React state — and it never changes once set.
    rootRef.current?.classList.add("hanok-js");
    rootRef.current?.setAttribute("data-season", season.season);
    window.parent?.postMessage(
      { type: "oneshot:ready", slug: "hanok" },
      "*",
    );
  }, [season.season]);

  return (
    <div
      ref={rootRef}
      className={`${nanumMyeongjo.variable} ${notoSerifKr.variable} ${jetbrainsMono.variable} hanok-root`}
    >
      <div className="hanok-page">
        <Hero />
        <main>
          <ExplodedAxonometric />
          <ClimateZones season={season} />
          <SeasonalLight season={season} />
          <JoineryDetail />
        </main>
        <HanokFooter />
      </div>

      {/* Wood grain: one static feTurbulence sheet multiplied over the whole
          page. The long horizontal fiber direction reads as sawn pine.
          Pointer-transparent, never animated. */}
      <div className="hanok-grain" aria-hidden="true">
        <svg width="100%" height="100%" preserveAspectRatio="none">
          <filter id="hanok-grain-f" x="0" y="0" width="100%" height="100%">
            <feTurbulence
              type="fractalNoise"
              baseFrequency="0.012 0.48"
              numOctaves="3"
              seed="7"
              stitchTiles="stitch"
            />
            <feColorMatrix
              type="matrix"
              values="0 0 0 0 0.24  0 0 0 0 0.18  0 0 0 0 0.11  0 0 0 0.06 0"
            />
          </filter>
          <rect width="100%" height="100%" filter="url(#hanok-grain-f)" />
        </svg>
      </div>
    </div>
  );
}

/* ==========================================================================
   HANOK — the building is the layout
   korean-traditional · unfinished pine + earthen wall + one dancheong eave-red
   Scoped by convention to .hanok-root; classes prefixed hanok-.
   The mortise-and-tenon joinery (no nails) becomes the grid system; the page
   has distinct climate zones — warm ondol (온돌방), cool maru (마루), open
   madang (마당) — and a curved-eave (처마) frame at the top.
   ========================================================================== */

.hanok-root {
  /* -- palette ----------------------------------------------------------- */
  --hanok-paper: #efe7d6;        /* earth-paper — the pale 흙벽 the atelier is drawn on */
  --hanok-ink: #3d2f1c;          /* ink-beam — darkened beam wood, all body text (10.5:1) */
  --hanok-wood: #c4a87a;         /* wood-raw — unfinished pine/hinoki; surfaces only */
  --hanok-beam: #6b5436;         /* beam-mid — structural beams + functional accent on light (5.8:1) */
  --hanok-wall: #d4c4a8;         /* earth-wall — 흙벽 fills inside structure and panels */
  --hanok-stone: #b8b0a4;        /* courtyard-stone — 마당 ground; decorative */
  --hanok-red: #9c3a2e;          /* eave-red — 단청 trim accent: focus, ::selection, eave line (5.6:1) */
  --hanok-red-deep: #7c2a20;     /* derived deeper red, used where red sits on warm/dark grounds */
  --hanok-ink-soft: #5a4a32;     /* secondary text — beam-mid darkened to AA body (6.6:1) */
  --hanok-ink-faint: #8a7459;    /* tertiary: large/uppercase labels only (3.4:1) */
  --hanok-sky: #e8e2d4;          /* sky-bone — open-sky/madang ground, cooler than paper */
  --hanok-snow: #f6f2e7;         /* winter overlay + maru cool deck */

  /* derived working tokens */
  --hanok-hairline: rgba(61, 47, 28, 0.16);          /* rules, grid lines */
  --hanok-hairline-strong: rgba(61, 47, 28, 0.34);   /* emphasized rules */
  --hanok-wall-soft: rgba(212, 196, 168, 0.55);      /* panel wash on paper */
  --hanok-wood-soft: rgba(196, 168, 122, 0.32);

  /* -- type --------------------------------------------------------------- */
  --hanok-font-serif: var(--font-nanum), var(--font-noto-kr), "Apple SD Gothic Neo",
    "Malgun Gothic", serif;
  --hanok-font-body: var(--font-noto-kr), "Apple SD Gothic Neo", "Malgun Gothic",
    serif;
  --hanok-font-mono: var(--font-jbmono), var(--font-noto-kr), "Courier New",
    monospace;

  /* -- motion ------------------------------------------------------------- */
  --hanok-ease-timber: cubic-bezier(0.16, 1, 0.3, 0.1);  /* structure settling */
  --hanok-ease-eave: cubic-bezier(0.65, 0, 0.35, 1);     /* curved-eave brush */

  /* -- season-driven (madang sky + eave shadow) --------------------------- */
  /* default = spring. data-season on the root swaps these. */
  --hanok-sky-tone: #e8e2d4;
  --hanok-sky-warm: #ece0c8;
  --hanok-eave-shadow: rgba(61, 47, 28, 0.22);
  --hanok-season-tag: #6b5436;

  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  background: var(--hanok-paper);
  color: var(--hanok-ink);
  font-family: var(--hanok-font-body);
  font-size: clamp(16px, 0.42vw + 14px, 18px);
  line-height: 1.6;
  overflow-x: hidden;
  overflow-x: clip;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}

/* -- Season palettes: only the madang sky ground + eave shadow recolor.
   Wood grain, earth wall, and all text hold still — wood and earth do not
   change with the season; only the light does. ------------------------- */

.hanok-root[data-season="spring"] {
  --hanok-sky-tone: #ece2cf;
  --hanok-sky-warm: #f0e3c9;
  --hanok-eave-shadow: rgba(61, 47, 28, 0.22);
  --hanok-season-tag: #6b5436;
}

.hanok-root[data-season="summer"] {
  --hanok-sky-tone: #dde4d2;
  --hanok-sky-warm: #e2e9d6;
  --hanok-eave-shadow: rgba(46, 58, 38, 0.18);
  --hanok-season-tag: #4f6044;
}

.hanok-root[data-season="autumn"] {
  --hanok-sky-tone: #e6d6bd;
  --hanok-sky-warm: #ecd2b0;
  --hanok-eave-shadow: rgba(92, 56, 28, 0.26);
  --hanok-season-tag: #8a4a1c;
}

.hanok-root[data-season="winter"] {
  --hanok-sky-tone: #eef0ec;
  --hanok-sky-warm: #f4f3ec;
  --hanok-eave-shadow: rgba(70, 84, 104, 0.16);
  --hanok-season-tag: #566275;
}

.hanok-root *,
.hanok-root *::before,
.hanok-root *::after {
  box-sizing: border-box;
}

/* Korean is first-class: Noto Serif KR everywhere Hangul appears, with
   keep-all so phrases never shatter mid-word. */
.hanok-root :lang(ko) {
  font-family: var(--hanok-font-body);
  word-break: keep-all;
  line-break: strict;
}

/* Eave-red selection, scoped to the entry root — the one place the
   dancheong trim pigment touches selection. */
.hanok-root ::selection {
  background: var(--hanok-red);
  color: var(--hanok-snow);
}

/* Keyboard focus: an eave-red ring. 3px solid clears the 3:1 non-text
   contrast minimum for UI components; offset lifts it off the target. */
.hanok-root :focus-visible {
  outline: 3px solid var(--hanok-red);
  outline-offset: 3px;
  border-radius: 2px;
}

/* ==========================================================================
   Page-wide wood-grain texture — one static feTurbulence sheet in multiply.
   The long horizontal fiber direction reads as sawn pine. Never animated.
   Pointer-transparent. Lives at the page root so every zone inherits it.
   ========================================================================== */

.hanok-grain {
  position: fixed;
  inset: 0;
  z-index: 1;
  pointer-events: none;
  mix-blend-mode: multiply;
  opacity: 0.6;
}

.hanok-page {
  position: relative;
  z-index: 2;
}

/* ==========================================================================
   Section headers — NN · title 한국어 — note
   The number sits like a folio stamped on a beam.
   ========================================================================== */

.hanok-sechead {
  display: flex;
  flex-wrap: wrap;
  align-items: baseline;
  gap: 0.45rem 1.2rem;
  margin-bottom: clamp(1.8rem, 4vh, 2.8rem);
  padding-bottom: 0.75rem;
  border-bottom: 1px solid var(--hanok-hairline);
}

.hanok-sechead__no {
  font-family: var(--hanok-font-mono);
  font-size: 0.78rem;
  letter-spacing: 0.18em;
  color: var(--hanok-red);
}

.hanok-sechead__title {
  margin: 0;
  font-family: var(--hanok-font-serif);
  font-size: clamp(1.4rem, 2.7vw, 2rem);
  font-weight: 700;
  letter-spacing: -0.005em;
}

.hanok-sechead__title [lang="ko"] {
  margin-left: 0.4rem;
  font-weight: 500;
  color: var(--hanok-ink-soft);
}

.hanok-sechead__note {
  margin: 0 0 0 auto;
  font-size: 0.85rem;
  color: var(--hanok-ink-soft);
}

.hanok-sechead__note [lang="ko"] {
  margin-left: 0.25rem;
}

/* ==========================================================================
   01 · Hero — the curved-eave frame over the building silhouette
   ========================================================================== */

.hanok-hero {
  position: relative;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-end;
  min-height: 100vh;
  min-height: 100svh;
  padding: clamp(56px, 9vh, 104px) clamp(20px, 5vw, 56px) clamp(28px, 4vh, 44px);
  text-align: center;
  background: linear-gradient(
    to bottom,
    var(--hanok-sky-warm) 0%,
    var(--hanok-paper) 62%
  );
  background-color: var(--hanok-paper);
  transition: background 600ms var(--hanok-ease-timber);
}

.hanok-hero__overline {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 0.3rem 1.6rem;
  margin: 0 0 auto;
  font-family: var(--hanok-font-mono);
  font-size: 0.72rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--hanok-ink-soft);
}

.hanok-hero__overline [lang="ko"] {
  margin-left: 0.3rem;
}

.hanok-hero__title {
  margin: clamp(2rem, 7vh, 4rem) 0 0.4rem;
  font-family: var(--hanok-font-serif);
  font-size: clamp(3.4rem, 13vw, 9rem);
  font-weight: 800;
  letter-spacing: 0.04em;
  line-height: 0.92;
  color: var(--hanok-ink);
}

/* The char-split reveal: each glyph settles on its own timer. aria-label
   on the wrapper holds the full string for AT; the spans are aria-hidden.
   Without .hanok-js every glyph is simply at rest (visible). */
.hanok-js .hanok-hero__title .hanok-char {
  display: inline-block;
  opacity: 0;
  transform: translateY(0.5em);
  animation: hanok-char-settle 820ms var(--hanok-ease-timber) forwards;
  animation-delay: var(--d, 0ms);
}

@keyframes hanok-char-settle {
  to {
    opacity: 1;
    transform: none;
  }
}

.hanok-hero__sub {
  margin: 0;
  font-family: var(--hanok-font-serif);
  font-size: clamp(1.05rem, 2.2vw, 1.5rem);
  font-weight: 400;
  color: var(--hanok-ink-soft);
}

.hanok-hero__tagline {
  margin: clamp(1.4rem, 3vh, 2rem) 0 0;
  max-width: 30ch;
  font-size: clamp(1.1rem, 2.2vw, 1.45rem);
  font-weight: 500;
  line-height: 1.5;
}

.hanok-hero__tagline [lang="ko"] {
  display: block;
  margin-top: 0.4rem;
  color: var(--hanok-ink-soft);
}

/* The curved-eave path with the bilingual subline riding it (textPath).
   text-path technique tag. The eave is the eave-red dancheong trim line. */
.hanok-hero__eave {
  display: block;
  width: min(560px, 92vw);
  height: auto;
  margin: clamp(2.4rem, 6vh, 3.6rem) auto 0;
}

.hanok-eave__curve {
  fill: none;
  stroke: var(--hanok-red);
  stroke-width: 2.4;
  stroke-linecap: round;
  /* draw-on: dasharray is the path length (set inline via pathLength=1);
     offset animates 1 → 0 once on mount under .hanok-js. */
}

.hanok-js .hanok-eave__curve {
  stroke-dasharray: 1;
  stroke-dashoffset: 1;
  animation: hanok-eave-draw 1.6s var(--hanok-ease-eave) 0.2s forwards;
}

@keyframes hanok-eave-draw {
  to {
    stroke-dashoffset: 0;
  }
