.hanok-hero__specline {
  margin: clamp(2rem, 4vh, 2.8rem) 0 0;
  font-family: var(--hanok-font-mono);
  font-size: 0.82rem;
  letter-spacing: 0.08em;
  color: var(--hanok-ink-soft);
}

.hanok-hero__specline [lang="ko"] {
  margin-left: 0.3rem;
}

.hanok-hero__hint {
  margin: clamp(1.6rem, 3vh, 2.2rem) 0 0;
  font-family: var(--hanok-font-mono);
  font-size: 0.68rem;
  letter-spacing: 0.24em;
  text-transform: uppercase;
  color: var(--hanok-ink-faint);
